import React from "react";
import { BrowserRouter, Routes, Route } from "react-router-dom";

import Layout from "./components/Layout";
import MaterialRequirement from "./components/MaterialRequirement";
import Dashboard from "./pages/Dashboard"; // ✅ only one

function App() {
  return (
    <BrowserRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/material" element={<MaterialRequirement />} />
        </Routes>
      </Layout>
    </BrowserRouter>
  );
}

export default App;
